import java.util.Random;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

public class MultithreadedMatrixMultiplication {
    private static final int ROWS = 3;
    private static final int COLS = 3;
    private static final int THREAD_COUNT = 4;

    public static void main(String[] args) {
        int[][] matrixA = generateMatrix(ROWS, COLS);
        int[][] matrixB = generateMatrix(COLS, ROWS);
        int[][] result = new int[ROWS][ROWS];
        ExecutorService executor = Executors.newFixedThreadPool(THREAD_COUNT);

        for (int i = 0; i < ROWS; i++) {
            for (int j = 0; j < ROWS; j++) {
                final int row = i;
                final int col = j;
                executor.execute(() -> computeCell(matrixA, matrixB, result, row, col));
            }
        }
        executor.shutdown();
        while (!executor.isTerminated()) {
            // Wait for threads to finish
        }
        displayMatrix(result);
    }

    private static int[][] generateMatrix(int rows, int cols) {
        Random random = new Random();
        int[][] matrix = new int[rows][cols];
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                matrix[i][j] = random.nextInt(10);
            }
        }
        return matrix;
    }

    private static synchronized void computeCell(int[][] matrixA, int[][] matrixB, int[][] result, int row, int col) {
        result[row][col] = 0;
        for (int k = 0; k < matrixB.length; k++) {
            result[row][col] += matrixA[row][k] * matrixB[k][col];
        }
    }

    private static void displayMatrix(int[][] matrix) {
        for (int[] row : matrix) {
            for (int value : row) {
                System.out.print(value + " ");
            }
            System.out.println();
        }
    }
}
