fn process_file(file_path: &str) -> Result<(), Box<dyn std::error::Error>> {
    let path = Path::new(file_path);
    let file = File::open(&path).map_err(|_| "File not found")?;
    let reader = BufReader::new(file);

    let mut word_counts = HashMap::new();

    for line in reader.lines() {
        let line = line?;
        for word in line.split_whitespace() {
            let word = word
                .to_lowercase()
                .chars()
                .filter(|c| c.is_alphanumeric())
                .collect::<String>();
            if !word.is_empty() {
                *word_counts.entry(word).or_insert(0) += 1;
            }
        }
    }

    let mut word_count_vec: Vec<_> = word_counts.into_iter().collect();
    word_count_vec.sort_by(|a, b| b.1.cmp(&a.1));

    println!("Top 5 most frequent words:");
    for (word, count) in word_count_vec.into_iter().take(5) {
        println!("{}: {}", word, count);
    }

    Ok(())
