#include <array>
#include <cstdint>
#include <cstddef>

constexpr uint32_t crc32_table[256] = []{
    constexpr uint32_t polynomial = 0xEDB88320;
    std::array<uint32_t, 256> table{};
    for (size_t i = 0; i < 256; ++i) {
        uint32_t crc = i;
        for (size_t j = 0; j < 8; ++j) {
            crc = (crc >> 1) ^ (polynomial * (crc & 1));
        }
        table[i] = crc;
    }
    return table;
}();

constexpr uint32_t crc32_impl(const char* data, size_t size, uint32_t crc = 0xFFFFFFFF) {
    for (size_t i = 0; i < size; ++i) {
        crc = (crc >> 8) ^ crc32_table[(crc ^ static_cast<uint8_t>(data[i])) & 0xFF];
    }
    return crc ^ 0xFFFFFFFF;
}

template <size_t N>
constexpr uint32_t crc32(const std::array<char, N>& arr) {
    return crc32_impl(arr.data(), N);
}

